// build-offer-architecture — Validate Upstream Inputs
// Checks all required upstream artifacts are present and well-formed.
// This node receives the full pipeline context from the orchestrator.
//
// CLOUD MODE: all data arrives inline via n8n pipeline. No filesystem access.

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const input = $input.first().json;
const strategySynthesis = input.strategy_synthesis;
const brandPositioning  = input.brand_positioning;
const marketIntelligence = input.market_intelligence;
const intakePayload     = input.normalized_intake_payload;
const runtimeConfig     = input.runtime_config;
const projectId         = input.project_id;

// Propagate cloud_mode from upstream
if (!cloudMode && runtimeConfig && runtimeConfig.cloud_mode) cloudMode = true;

// Required presence checks
if (!strategySynthesis) {
  throw new Error('MISSING_ARTIFACT: strategy_synthesis is required. Run build-strategy-synthesis first.');
}
if (!strategySynthesis.growth_thesis) {
  throw new Error('MISSING_ARTIFACT: strategy_synthesis.growth_thesis is required.');
}
if (!strategySynthesis.positioning_focus) {
  throw new Error('MISSING_ARTIFACT: strategy_synthesis.positioning_focus is required.');
}
if (!Array.isArray(strategySynthesis.opportunity_priorities) || strategySynthesis.opportunity_priorities.length === 0) {
  throw new Error('MISSING_ARTIFACT: strategy_synthesis.opportunity_priorities must be a non-empty array.');
}
if (!brandPositioning || !brandPositioning.value_proposition) {
  throw new Error('MISSING_ARTIFACT: brand_positioning with value_proposition is required. Run build-brand-positioning first.');
}
if (!intakePayload) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload is required. Run intake-store-input first.');
}
if (!intakePayload.price_positioning) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload.price_positioning is required.');
}
if (!intakePayload.vertical) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload.vertical is required.');
}
if (!runtimeConfig) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config is required.');
}
if (!projectId) {
  throw new Error('MISSING_INPUT: project_id is required.');
}

console.log('build-offer-architecture: inputs validated. cloud=' + cloudMode + ' project=' + projectId);

return [{
  json: {
    project_id:                 projectId,
    runtime_config:             runtimeConfig,
    strategy_synthesis:         strategySynthesis,
    brand_positioning:          brandPositioning,
    market_intelligence:        marketIntelligence || null,
    normalized_intake_payload:  intakePayload,
    cloud_mode:                 cloudMode,
  },
}];

// build-offer-architecture — Build LLM Synthesis Prompt
// Extracts signals from strategy_synthesis + brand_positioning + market_intelligence
// and assembles a structured prompt for offer architecture generation.
//
// Evidence boundary:
//   - LLM inference from internal signals only.
//   - No external research, no crawling.
//   - All outputs are planning hypotheses requiring human verification.

const input = $input.first().json;
const ss    = input.strategy_synthesis;
const bp    = input.brand_positioning;
const mi    = input.market_intelligence || {};
const ip    = input.normalized_intake_payload;
const cloudMode = input.cloud_mode || false;

// ─── Extract Strategy Synthesis signals ──────────────────────────────────────
const growthThesis = ss.growth_thesis || {};
const growthStatement = typeof growthThesis === 'string' ? growthThesis
  : (growthThesis.statement || JSON.stringify(growthThesis));
const growthRationale = typeof growthThesis === 'object' ? (growthThesis.rationale || '') : '';

const positioningFocus = ss.positioning_focus || {};
const positioningAngle = typeof positioningFocus === 'string' ? positioningFocus
  : (positioningFocus.primary_angle || JSON.stringify(positioningFocus));

const opportunities = (ss.opportunity_priorities || []).slice(0, 4).map(function(o) {
  return typeof o === 'string' ? o : (o.opportunity || JSON.stringify(o));
});
const risks = (ss.risk_priorities || []).slice(0, 3).map(function(r) {
  return typeof r === 'string' ? r : (r.risk || JSON.stringify(r));
});
const offerImplications = (ss.offer_implications || []).slice(0, 4);
const moatHypotheses = (ss.moat_hypotheses || []).slice(0, 3).map(function(m) {
  return typeof m === 'string' ? m : (m.hypothesis || JSON.stringify(m));
});

// ─── Extract Brand Positioning signals ───────────────────────────────────────
const valueProposition  = bp.value_proposition || '';
const positioningStmt   = bp.positioning_statement || '';
const differentiators   = (bp.differentiators || []).slice(0, 5);
const brandRole         = bp.brand_role || 'specialist';
const messagingPillars  = (bp.messaging_pillars || []).slice(0, 3).map(function(p) {
  return typeof p === 'string' ? p : (p.pillar_name + (p.description ? ': ' + p.description.slice(0, 80) : ''));
});

// ─── Extract intake signals ───────────────────────────────────────────────────
const pricePositioning  = ip.price_positioning || 'unknown';
const vertical          = ip.vertical || 'unknown';
const primaryMarket     = ip.primary_market || 'unknown';
const storeType         = ip.store_type || 'unknown';
const projectName       = ip.project_name || ip.project_id || 'unknown';

// ─── Extract Market Intelligence signals (optional) ──────────────────────────
const priceBandLogic    = mi.price_band_logic || null;
const purchaseMotivators = (mi.purchase_motivators || []).slice(0, 3).map(function(m) {
  return typeof m === 'string' ? m : (m.motivator || JSON.stringify(m));
});
const audienceSegments  = (mi.audience_segments || []).slice(0, 2).map(function(s) {
  return typeof s === 'string' ? s : ((s.segment_name || 'segment') + (s.description ? ': ' + String(s.description).slice(0, 80) : ''));
});

// ─── Build prompt ─────────────────────────────────────────────────────────────
const prompt = [
  'You are a senior e-commerce strategist building the offer architecture for a new Shopify store.',
  'Based on the strategic intelligence below, generate a structured offer architecture.',
  '',
  '## Store Context',
  'Project: ' + projectName,
  'Vertical: ' + vertical,
  'Price positioning: ' + pricePositioning,
  'Store type: ' + storeType,
  'Market: ' + primaryMarket,
  '',
  '## Strategic Intelligence',
  '### Growth Thesis',
  growthStatement,
  growthRationale ? ('Rationale: ' + growthRationale) : '',
  '',
  '### Positioning Focus',
  positioningAngle,
  '',
  '### Brand Value Proposition',
  valueProposition,
  positioningStmt ? ('Positioning: ' + positioningStmt) : '',
  '',
  '### Key Differentiators',
  differentiators.slice(0, 5).map(function(d, i) { return (i+1) + '. ' + (typeof d === 'string' ? d : JSON.stringify(d)); }).join('\n'),
  '',
  opportunities.length ? ('### Opportunities to Exploit\n' + opportunities.map(function(o, i) { return (i+1) + '. ' + o; }).join('\n')) : '',
  risks.length ? ('### Risks to Mitigate\n' + risks.map(function(r, i) { return (i+1) + '. ' + r; }).join('\n')) : '',
  offerImplications.length ? ('### Strategic Offer Implications\n' + offerImplications.map(function(i) { return '- ' + i; }).join('\n')) : '',
  moatHypotheses.length ? ('### Moat Hypotheses\n' + moatHypotheses.map(function(m) { return '- ' + m; }).join('\n')) : '',
  messagingPillars.length ? ('### Brand Messaging Pillars\n' + messagingPillars.map(function(p) { return '- ' + p; }).join('\n')) : '',
  purchaseMotivators.length ? ('### Purchase Motivators\n' + purchaseMotivators.map(function(m) { return '- ' + m; }).join('\n')) : '',
  priceBandLogic ? ('### Price Band Context\n' + (typeof priceBandLogic === 'string' ? priceBandLogic : JSON.stringify(priceBandLogic))) : '',
  audienceSegments.length ? ('### Audience Segments\n' + audienceSegments.map(function(s) { return '- ' + s; }).join('\n')) : '',
  '',
  '## Output Requirements',
  'Return a JSON object with exactly this structure (no markdown fences):',
  '{',
  '  "core_offer": {',
  '    "headline": "One-line offer statement for the store",',
  '    "value_proposition": "Why this offer wins for the target buyer",',
  '    "target_buyer": "Specific buyer persona or segment description",',
  '    "proof_points": ["Evidence point 1", "Evidence point 2", "Evidence point 3"]',
  '  },',
  '  "pricing_logic": {',
  '    "tier": "' + pricePositioning + '",',
  '    "anchor_strategy": "How price anchoring is used",',
  '    "price_range_signal": "Indicative price range language for this category",',
  '    "bulk_pricing": true/false,',
  '    "subscription_model": true/false',
  '  },',
  '  "bundle_opportunities": [',
  '    { "name": "Bundle name", "rationale": "Why this bundle works", "components": ["Product A", "Product B"], "estimated_uplift": "e.g. +15% AOV" }',
  '  ],',
  '  "upsell_paths": [',
  '    { "from": "Entry product/category", "to": "Upsell target", "trigger": "When/why this upsell appears" }',
  '  ],',
  '  "offer_narrative": "1-3 paragraph narrative synthesising the offer architecture for content and GTM use.",',
  '  "offer_gaps": ["Gap or unknown that needs merchant input"],',
  '  "validation_questions": ["Question requiring merchant validation before launch"]',
  '}',
  '',
  'Rules:',
  '- pricing_logic.tier must be exactly: "' + pricePositioning + '"',
  '- bundle_opportunities: at least 1 item, at most 5',
  '- upsell_paths: at least 1 item, at most 5',
  '- proof_points: at least 2 items',
  '- offer_narrative: 2-4 sentences minimum',
  '- All values must be grounded in the provided strategic intelligence',
  '- Return pure JSON only, no markdown fences, no commentary outside the JSON',
].filter(function(l) { return l !== null && l !== undefined; }).join('\n');

return [{
  json: {
    llm_prompt:                 prompt,
    project_id:                 input.project_id,
    runtime_config:             input.runtime_config,
    strategy_synthesis:         ss,
    brand_positioning:          bp,
    market_intelligence:        mi,
    normalized_intake_payload:  ip,
    cloud_mode:                 cloudMode,
    price_positioning:          pricePositioning,
  },
}];

// build-offer-architecture — Parse, Validate, and Write
//
// Steps:
//   1. Parse LLM JSON object response
//   2. Inline schema validation (required fields, structure checks)
//   3. Return offer_architecture inline with runtime envelope
//
// CLOUD MODE: fully compatible. No AJV, no filesystem write.
// SELF-HOSTED: same path (artifact write planned for future phase).

function buildRunId() {
  const ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);
  const rand = Math.random().toString(36).slice(2, 6);
  return 'run-' + ts + '-' + rand;
}

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const llmOutput = $input.first().json;
const upstream  = $node['Build LLM Synthesis Prompt'].json;

if (!cloudMode && upstream.cloud_mode) cloudMode = true;
if (!cloudMode && upstream.runtime_config && upstream.runtime_config.cloud_mode) cloudMode = true;

const projectId         = upstream.project_id;
const runtimeConfig     = upstream.runtime_config;
const strategySynthesis = upstream.strategy_synthesis;
const brandPositioning  = upstream.brand_positioning;
const pricePositioning  = upstream.price_positioning;

// ─── Step 1: Parse LLM response ──────────────────────────────────────────────
const rawText = (llmOutput.message && llmOutput.message.content)
  ? llmOutput.message.content
  : (typeof llmOutput === 'string' ? llmOutput : JSON.stringify(llmOutput));

let offerArch;
try {
  let cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  }
  const parsed = JSON.parse(cleaned);
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
    offerArch = parsed;
  } else {
    throw new Error('Expected a JSON object at root, got: ' + typeof parsed);
  }
} catch (err) {
  throw new Error(
    'LLM_PARSE_ERROR: Failed to parse LLM response as JSON object: ' + err.message +
    '. Raw response (first 500 chars): ' + String(rawText).slice(0, 500)
  );
}

// ─── Step 2: Inline schema validation ────────────────────────────────────────
const cloudWarnings = [];

// Required top-level fields
const REQUIRED = ['core_offer', 'pricing_logic', 'bundle_opportunities', 'upsell_paths', 'offer_narrative'];
for (const f of REQUIRED) {
  if (!offerArch[f]) {
    throw new Error('SCHEMA_VIOLATION: offer_architecture.' + f + ' is required.');
  }
}

// core_offer required subfields
const CORE_OFFER_REQUIRED = ['headline', 'value_proposition', 'target_buyer'];
for (const f of CORE_OFFER_REQUIRED) {
  if (!offerArch.core_offer[f]) {
    throw new Error('SCHEMA_VIOLATION: offer_architecture.core_offer.' + f + ' is required.');
  }
}
if (!Array.isArray(offerArch.core_offer.proof_points) || offerArch.core_offer.proof_points.length < 2) {
  throw new Error('SCHEMA_VIOLATION: offer_architecture.core_offer.proof_points must have at least 2 items.');
}

// pricing_logic required subfields
if (!offerArch.pricing_logic.tier) {
  throw new Error('SCHEMA_VIOLATION: offer_architecture.pricing_logic.tier is required.');
}
if (!offerArch.pricing_logic.anchor_strategy) {
  throw new Error('SCHEMA_VIOLATION: offer_architecture.pricing_logic.anchor_strategy is required.');
}
const PRICE_TIER_ENUM = ['budget', 'mass-market', 'mass-premium', 'premium', 'luxury'];
if (!PRICE_TIER_ENUM.includes(offerArch.pricing_logic.tier)) {
  // Attempt auto-correct from intake price_positioning
  if (pricePositioning && PRICE_TIER_ENUM.includes(pricePositioning)) {
    console.warn('SCHEMA_WARN: pricing_logic.tier "' + offerArch.pricing_logic.tier + '" is not valid — corrected to "' + pricePositioning + '"');
    cloudWarnings.push('pricing_logic.tier auto-corrected from "' + offerArch.pricing_logic.tier + '" to "' + pricePositioning + '"');
    offerArch.pricing_logic.tier = pricePositioning;
  } else {
    throw new Error('SCHEMA_VIOLATION: pricing_logic.tier "' + offerArch.pricing_logic.tier + '" is not valid. Must be one of: ' + PRICE_TIER_ENUM.join(', '));
  }
}

// bundle_opportunities: array, min 1
if (!Array.isArray(offerArch.bundle_opportunities) || offerArch.bundle_opportunities.length < 1) {
  throw new Error('SCHEMA_VIOLATION: offer_architecture.bundle_opportunities must be a non-empty array.');
}
for (let i = 0; i < offerArch.bundle_opportunities.length; i++) {
  const b = offerArch.bundle_opportunities[i];
  if (!b.name || !b.rationale) {
    throw new Error('SCHEMA_VIOLATION: bundle_opportunities[' + i + '] must have name and rationale.');
  }
}

// upsell_paths: array, min 1
if (!Array.isArray(offerArch.upsell_paths) || offerArch.upsell_paths.length < 1) {
  throw new Error('SCHEMA_VIOLATION: offer_architecture.upsell_paths must be a non-empty array.');
}
for (let i = 0; i < offerArch.upsell_paths.length; i++) {
  const u = offerArch.upsell_paths[i];
  if (!u.from || !u.to || !u.trigger) {
    throw new Error('SCHEMA_VIOLATION: upsell_paths[' + i + '] must have from, to, and trigger.');
  }
}

// offer_narrative: non-empty string
if (typeof offerArch.offer_narrative !== 'string' || offerArch.offer_narrative.trim().length < 50) {
  throw new Error('SCHEMA_VIOLATION: offer_architecture.offer_narrative must be a non-empty string (min 50 chars).');
}

// ─── Step 3: Build runtime envelope ──────────────────────────────────────────
const runId       = buildRunId();
const executionTs = new Date().toISOString();

const outputSummary = {
  bundle_count:          offerArch.bundle_opportunities.length,
  upsell_path_count:     offerArch.upsell_paths.length,
  proof_point_count:     (offerArch.core_offer.proof_points || []).length,
  offer_gap_count:       (offerArch.offer_gaps || []).length,
  validation_q_count:    (offerArch.validation_questions || []).length,
  pricing_tier:          offerArch.pricing_logic.tier,
  bulk_pricing:          offerArch.pricing_logic.bulk_pricing || false,
  subscription_model:    offerArch.pricing_logic.subscription_model || false,
};

const envelope = {
  run_id:     runId,
  phase:      'offer-architecture',
  project_id: projectId,
  timestamp:  executionTs,
  cloud_mode: cloudMode,
  validation: {
    result:    'PASS',
    errors:    [],
    warnings:  cloudWarnings,
  },
  diagnostics: {
    output_summary: outputSummary,
  },
  lineage: {
    depends_on: ['build-strategy-synthesis', 'build-brand-positioning'],
    produced_by: 'build-offer-architecture',
  },
};

// ─── Return ───────────────────────────────────────────────────────────────────
return [{
  json: {
    project_id:       projectId,
    artifact_name:    'offer-architecture',
    artifact_path:    null,
    offer_architecture: offerArch,
    runtime_config:   runtimeConfig,
    status:           'SUCCESS',
    cloud_mode:       cloudMode,
    cloud_warnings:   cloudWarnings,
    notes:            [],
    envelope:         envelope,
  },
}];
